Next, let's create a service that will handle authentication. Create a new file called `auth.service.ts` in your `src/services` directory and add the following code:

```typescript
import { Injectable } from '@nestjs/common';
import * as jwt from 'jsonwebtoken';

@Injectable()
export class AuthService {
  private secretKey = 'your-secret-key'; // Replace with your secret key

  async generateToken(user: any): Promise<string> {
    const token = jwt.sign(user, this.secretKey, { expiresIn: '1h' });
    return token;
  }

  async verifyToken(token: string): Promise<any> {
    try {
      const decoded = jwt.verify(token, this.secretKey);
      return decoded;
    } catch (error) {
      return null;
    }
  }
}
```

